<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function edError(m){$('.isi_warning_delete').text(m||'Employee Document gagal diproses.');$('.error_data_delete').fadeIn();}
function edFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),document_type:$('#filter_document_type').val(),document_category:$('#filter_document_category').val(),verification_status:$('#filter_verification_status').val(),status:$('#filter_status').val(),expiring_soon:$('#filter_expiring_soon').val(),keyword:$('#filter_keyword').val()};}
function edSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function edReset(title){$('#form_employee_document')[0].reset();$('#ed_id').val('');$('#employee_id,#verified_by_employee_id').val(null).trigger('change');$('#document_type').val('KTP').trigger('change');$('#document_category').val('PERSONAL').trigger('change');$('#confidential,#mandatory_document,#renewal_required').val('N').trigger('change');$('#verification_status').val('PENDING').trigger('change');$('#status').val('ACTIVE').trigger('change');$('#issuing_country').val('ID');$('#effective_from').val('<?=$defaultFrom;?>');$('#effective_to').val('<?=$defaultTo;?>');$('#modal_employee_document .modal-title').text(title||'Create Employee Document');}
function edAjax(s,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:$('#modal_employee_document'),ajax:{url:'<?=base_admin();?>modul/employee_document/employee_document_action.php?act=employee_search',type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.ed-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_document_type,#filter_document_category,#filter_verification_status,#filter_status,#filter_expiring_soon,#document_type,#document_category,#file_type,#confidential,#mandatory_document,#renewal_required,#verification_status,#status').select2({width:'100%',allowClear:true});edAjax('#employee_id','Pilih Employee...');edAjax('#verified_by_employee_id','Pilih Verifier...');}
var dt=$('#dtb_employee_document').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/employee_document/employee_document_data.php',type:'post',data:function(d){$.extend(d,edFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_pending').text(k.pending||0);$('#kpi_confidential').text(k.confidential||0);$('#kpi_expiring_soon').text(k.expiring_soon||0);return j.data||[];},error:function(x){console.log(x.responseText);edError('Data Employee Document gagal dimuat.');}}});
$('#btn_open_ed').click(function(){edReset('Create Employee Document');$('#modal_employee_document').modal({backdrop:'static',keyboard:false});});$('#btn_filter_ed').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ed').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_document_type,#filter_document_category,#filter_verification_status,#filter_status,#filter_expiring_soon').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_ed').click(function(){window.location='<?=base_admin();?>modul/employee_document/employee_document_action.php?act=export&'+$.param(edFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#document_no,#issuing_country,#file_type').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#form_employee_document').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/employee_document/employee_document_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Document');if(r.status==='good'){$('#modal_employee_document').modal('hide');dt.draw(false);Swal.fire('Saved',<?=hr_js('hr_employee_document_save_success', 'Employee Document saved successfully.');?>,'success');}else edError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Document');edError(x.responseText);});});
$(document).on('click','.btn-ed-detail',function(){$.post('<?=base_admin();?>modul/employee_document/employee_document_action.php?act=detail',{id:$(this).data('id')},function(h){$('#ed_detail_body').html(h);$('#modal_ed_detail').modal('show');});});
$(document).on('click','.btn-ed-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/employee_document/employee_document_action.php?act=get',{id:id},function(r){if(r.status!=='good'){edError(r.error_message);return;}edReset('Edit Employee Document');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['employee_id','verified_by_employee_id'].includes(k))el.val(h[k]);});$('#ed_id').val(h.id);edSet('#employee_id',h.employee_id,h.employee_text);edSet('#verified_by_employee_id',h.verified_by_employee_id,h.verified_by_text);$('#document_type,#document_category,#file_type,#confidential,#mandatory_document,#renewal_required,#verification_status,#status').trigger('change');$('#modal_employee_document').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-ed-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/employee_document/employee_document_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else edError(r.error_message);},'json');});
$(document).on('click','.btn-ed-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/employee_document/employee_document_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else edError(r.error_message);},'json').fail(function(x){edError(x.responseText);});});});
});
</script>
